def eval_expr(s):
    toks = re.findall(r'\d+|[+*-]', s)
    nums = [int(toks[0])]; ops = []; i = 1
    while i < len(toks):
        if toks[i] == '*': nums[-1] *= int(toks[i+1])
        else: nums.append(int(toks[i+1])); ops.append(toks[i])
